CREATE ALGORITHM=UNDEFINED DEFINER=`neolab`@`%` SQL SECURITY DEFINER VIEW `v_hist_eventos_12m` AS select `v_hist_ventas`.`FAC` AS `FAC`,`v_hist_ventas`.`Fecha` AS `Fecha`,`v_hist_ventas`.`Anio` AS `Anio`,`v_hist_ventas`.`YearMonth` AS `YearMonth`,`v_hist_ventas`.`SKU` AS `SKU`,`v_hist_ventas`.`ClienteN` AS `ClienteN`,`v_hist_ventas`.`ClienteNombre` AS `ClienteNombre`,`v_hist_ventas`.`Qty` AS `Qty`,`v_hist_ventas`.`UnitPrice_USD` AS `UnitPrice_USD`,`v_hist_ventas`.`UnitCost_USD` AS `UnitCost_USD`,`v_hist_ventas`.`Revenue_USD` AS `Revenue_USD`,`v_hist_ventas`.`Margin_USD` AS `Margin_USD` from `v_hist_ventas` where (`v_hist_ventas`.`Fecha` >= (curdate() - interval 12 month))